import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';
import Auth from './Auth';

function App() {
  // === ESTADOS DO SISTEMA ===
  const [view, setView] = useState('home'); 
  const [activeTab, setActiveTab] = useState('confrontos'); 
  const [user, setUser] = useState(null);

  // === ESTADOS DE DADOS ===
  const [campeonatos, setCampeonatos] = useState([]);
  const [campeonatoAtivo, setCampeonatoAtivo] = useState(null);
  const [times, setTimes] = useState([]);
  const [partidas, setPartidas] = useState([]);
  const [admins, setAdmins] = useState([]);
  
  // === ESTADOS DE FORMULÁRIOS ===
  const [nome, setNome] = useState('');
  const [formato, setFormato] = useState('pontos-corridos'); // Garantindo o valor padrão
  const [qtdTimes, setQtdTimes] = useState(16);
  const [nomeTime, setNomeTime] = useState('');
  const [nomeResponsavel, setNomeResponsavel] = useState('');
  const [escudoFile, setEscudoFile] = useState(null); 
  const [uploading, setUploading] = useState(false);
  const [novoAdminEmail, setNovoAdminEmail] = useState('');

  // === MONITOR DE SESSÃO ===
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
    });
    return () => subscription.unsubscribe();
  }, []);

  // === CARREGAMENTO DE DADOS ===
  const carregarCampeonatos = async () => {
    const { data, error } = await supabase.from('campeonatos').select('*').order('created_at', { ascending: false });
    if (error) console.error("Erro ao carregar:", error.message);
    if (data) setCampeonatos(data);
  };

  useEffect(() => { carregarCampeonatos(); }, [user]);

  const carregarDadosCampeonato = async (champ) => {
    setCampeonatoAtivo(champ);
    const { data: t } = await supabase.from('times').select('*').eq('campeonato_id', champ.id).order('created_at', { ascending: true });
    if (t) setTimes(t);
    const { data: p } = await supabase.from('partidas').select(`*, time_casa:time_casa_id(nome, escudo_url), time_fora:time_fora_id(nome, escudo_url)`).eq('campeonato_id', champ.id).order('rodada', { ascending: true });
    if (p) setPartidas(p);
    const { data: a } = await supabase.from('administradores').select('*').eq('campeonato_id', champ.id);
    if (a) setAdmins(a);
    setView('detalhes');
  };

  // === AÇÕES DE ESCRITA ===
  const criarCampeonatoReal = async (e) => {
    e.preventDefault();
    if (!user) return alert("Faça login primeiro!");

    const { data, error } = await supabase.from('campeonatos').insert([{ 
      nome, 
      formato, 
      qtd_times: qtdTimes, 
      criador_id: user.id 
    }]).select();

    if (error) {
      alert("Erro do Banco: " + error.message);
    } else {
      setNome('');
      carregarCampeonatos(); 
      setView('home');
    }
  };

  const adicionarTime = async (e) => {
    e.preventDefault();
    setUploading(true);
    let escudoUrl = null;
    if (escudoFile) {
      const fileName = `${Math.random()}.${escudoFile.name.split('.').pop()}`;
      const { error: upErr } = await supabase.storage.from('escudos').upload(fileName, escudoFile);
      if (!upErr) {
        const { data: pUrl } = supabase.storage.from('escudos').getPublicUrl(fileName);
        escudoUrl = pUrl.publicUrl;
      }
    }
    await supabase.from('times').insert([{ campeonato_id: campeonatoAtivo.id, nome: nomeTime, jogador_responsavel: nomeResponsavel, escudo_url: escudoUrl }]);
    setNomeTime(''); setNomeResponsavel(''); setEscudoFile(null);
    setUploading(false);
    carregarDadosCampeonato(campeonatoAtivo);
  };

  const adicionarAdmin = async (e) => {
    e.preventDefault();
    const { error } = await supabase.from('administradores').insert([{ campeonato_id: campeonatoAtivo.id, user_email: novoAdminEmail }]);
    if (!error) { setNovoAdminEmail(''); carregarDadosCampeonato(campeonatoAtivo); }
    else { alert("Apenas o criador original pode adicionar admins."); }
  };

  const atualizarPlacar = async (id, gc, gf) => {
    await supabase.from('partidas').update({ gols_casa: gc, gols_fora: gf, status: 'finalizado' }).eq('id', id);
    carregarDadosCampeonato(campeonatoAtivo);
  };

  const gerarTabelaJogos = async () => {
    let ts = [...times];
    if (ts.length % 2 !== 0) ts.push({ id: null, nome: 'FOLGA' });
    const rounds = ts.length - 1;
    const half = ts.length / 2;
    const matches = [];
    for (let r = 1; r <= rounds; r++) {
      for (let i = 0; i < half; i++) {
        const casa = ts[i]; const fora = ts[ts.length - 1 - i];
        if (casa.id && fora.id) matches.push({ campeonato_id: campeonatoAtivo.id, time_casa_id: casa.id, time_fora_id: fora.id, rodada: r, status: 'agendado' });
      }
      ts.splice(1, 0, ts.pop());
    }
    await supabase.from('partidas').insert(matches);
    carregarDadosCampeonato(campeonatoAtivo);
  };

  const calcularClassificacao = () => {
    const tabela = times.map(time => {
      let s = { ...time, p: 0, j: 0, v: 0, e: 0, d: 0, gp: 0, gc: 0, sg: 0 };
      partidas.filter(m => m.status === 'finalizado').forEach(m => {
        if (m.time_casa_id === time.id) {
          s.j++; s.gp += m.gols_casa; s.gc += m.gols_fora;
          if (m.gols_casa > m.gols_fora) { s.v++; s.p += 3; }
          else if (m.gols_casa === m.gols_fora) { s.e++; s.p += 1; }
          else s.d++;
        } else if (m.time_fora_id === time.id) {
          s.j++; s.gp += m.gols_fora; s.gc += m.gols_casa;
          if (m.gols_fora > m.gols_casa) { s.v++; s.p += 3; }
          else if (m.gols_casa === m.gols_fora) { s.e++; s.p += 1; }
          else s.d++;
        }
      });
      s.sg = s.gp - s.gc;
      return s;
    });
    return tabela.sort((a, b) => b.p - a.p || b.sg - a.sg);
  };

  // === PERMISSÕES ===
  const isOwner = user && campeonatoAtivo && user.id === campeonatoAtivo.criador_id;
  const isAdmin = user && admins.some(a => a.user_email === user.email);
  const canEdit = isOwner || isAdmin;

  return (
    <div className="min-h-screen bg-ef-dark text-white font-sans">
      <nav className="border-b border-gray-800 p-4 flex justify-between items-center bg-ef-card sticky top-0 z-50">
        <h1 className="text-2xl font-bold italic text-ef-green cursor-pointer" onClick={() => setView('home')}>eFOOTBALL CHAMP</h1>
        <div className="flex items-center space-x-4">
          {user ? (
            <button onClick={() => supabase.auth.signOut()} className="text-red-500 text-xs font-bold">SAIR ({user.email.split('@')[0]})</button>
          ) : (
            <button onClick={() => setView('login')} className="bg-ef-green text-black px-4 py-2 rounded-full font-bold text-xs uppercase">Entrar</button>
          )}
        </div>
      </nav>

      <main className="p-6 max-w-7xl mx-auto">
        {view === 'login' && <Auth onLogin={() => { setView('home'); carregarCampeonatos(); }} />}

        {view === 'home' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {campeonatos.map(c => (
              <div key={c.id} className="bg-ef-card p-6 rounded-2xl border border-gray-800 flex flex-col justify-between hover:border-ef-green transition">
                <h3 className="text-xl font-bold italic uppercase text-ef-green">{c.nome}</h3>
                <button onClick={() => carregarDadosCampeonato(c)} className="mt-6 w-full py-2 bg-gray-800 text-white font-bold rounded-lg hover:bg-ef-green hover:text-black transition uppercase text-sm">Gerenciar</button>
              </div>
            ))}
            <div onClick={() => user ? setView('criar') : setView('login')} className="border-2 border-dashed border-gray-800 p-6 rounded-2xl flex items-center justify-center text-gray-500 cursor-pointer hover:border-ef-green hover:text-ef-green transition h-40">
              + CRIAR NOVO TORNEIO
            </div>
          </div>
        )}

        {view === 'criar' && (
          <div className="max-w-md mx-auto bg-ef-card p-8 rounded-2xl border border-gray-800">
            <h2 className="text-2xl font-bold mb-6 text-ef-green italic uppercase text-center">Configurar Torneio</h2>
            <form onSubmit={criarCampeonatoReal} className="space-y-4">
              <input required value={nome} onChange={e => setNome(e.target.value)} placeholder="NOME DO CAMPEONATO" className="w-full bg-ef-dark p-3 rounded border border-gray-700 outline-none focus:border-ef-green" />
              
              <select value={formato} onChange={e => setFormato(e.target.value)} className="w-full bg-ef-dark p-3 rounded border border-gray-700 outline-none focus:border-ef-green">
                <option value="pontos-corridos">Pontos Corridos (Liga)</option>
                <option value="mata-mata">Mata-Mata (Copa)</option>
              </select>

              <input required type="number" value={qtdTimes} onChange={e => setQtdTimes(e.target.value)} placeholder="QTD DE TIMES" className="w-full bg-ef-dark p-3 rounded border border-gray-700 outline-none focus:border-ef-green" />
              
              <div className="flex gap-2">
                <button type="button" onClick={() => setView('home')} className="flex-1 py-3 bg-gray-800 rounded-lg font-bold">CANCELAR</button>
                <button type="submit" className="flex-1 py-3 bg-ef-green text-black font-bold rounded-lg uppercase">CRIAR AGORA</button>
              </div>
            </form>
          </div>
        )}

        {view === 'detalhes' && campeonatoAtivo && (
          <div>
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-3xl font-black text-ef-green italic uppercase">{campeonatoAtivo.nome}</h2>
              {canEdit && partidas.length === 0 && times.length > 1 && (
                <button onClick={gerarTabelaJogos} className="bg-ef-green text-black px-6 py-2 rounded-full font-bold uppercase text-xs">Gerar Tabela de Jogos</button>
              )}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
              <div className="space-y-6">
                {canEdit && (
                  <div className="bg-ef-card p-5 rounded-xl border border-gray-800">
                    <h4 className="font-bold mb-4 text-xs uppercase text-gray-400">Novo Time</h4>
                    <form onSubmit={adicionarTime} className="space-y-3">
                      <input required value={nomeTime} onChange={e => setNomeTime(e.target.value)} placeholder="Nome do Time" className="w-full bg-ef-dark p-2 rounded text-sm border border-gray-700 outline-none" />
                      <input value={nomeResponsavel} onChange={e => setNomeResponsavel(e.target.value)} placeholder="Jogador" className="w-full bg-ef-dark p-2 rounded text-sm border border-gray-700 outline-none" />
                      <input type="file" onChange={e => setEscudoFile(e.target.files[0])} className="text-[10px] text-gray-500 w-full" />
                      <button disabled={uploading} className="w-full py-2 bg-ef-green text-black font-bold rounded text-xs uppercase">{uploading ? 'Salvando...' : 'Adicionar'}</button>
                    </form>
                  </div>
                )}

                {isOwner && (
                  <div className="bg-ef-card p-5 rounded-xl border border-gray-800">
                    <h4 className="font-bold mb-4 text-xs uppercase text-gray-400 italic">Convidar Admins</h4>
                    <form onSubmit={adicionarAdmin} className="flex space-x-2">
                      <input required value={novoAdminEmail} onChange={e => setNovoAdminEmail(e.target.value)} placeholder="Email do amigo" className="flex-1 bg-ef-dark p-2 rounded text-xs border border-gray-700 outline-none" />
                      <button className="bg-ef-green text-black px-3 rounded font-bold text-xs">+</button>
                    </form>
                  </div>
                )}
                
                <div className="bg-ef-card p-5 rounded-xl border border-gray-800">
                  <h4 className="font-bold mb-4 text-xs uppercase text-gray-400 italic">Times ({times.length}/{campeonatoAtivo.qtd_times})</h4>
                  <div className="space-y-2">
                    {times.map(t => (
                      <div key={t.id} className="flex items-center p-2 bg-ef-dark rounded border border-gray-800">
                        {t.escudo_url ? <img src={t.escudo_url} className="w-6 h-6 rounded-full mr-3" /> : <div className="w-6 h-6 bg-gray-700 rounded-full mr-3" />}
                        <span className="text-sm font-bold truncate">{t.nome}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="lg:col-span-3">
                <div className="flex space-x-4 mb-6 bg-ef-card p-1 rounded-full w-max border border-gray-800">
                  <button onClick={() => setActiveTab('confrontos')} className={`px-6 py-2 rounded-full font-bold text-xs uppercase ${activeTab === 'confrontos' ? 'bg-ef-green text-black' : 'text-gray-400'}`}>Jogos</button>
                  <button onClick={() => setActiveTab('tabela')} className={`px-6 py-2 rounded-full font-bold text-xs uppercase ${activeTab === 'tabela' ? 'bg-ef-green text-black' : 'text-gray-400'}`}>Tabela</button>
                </div>

                {activeTab === 'confrontos' && (
                  <div className="space-y-6">
                    {partidas.length === 0 ? <div className="text-gray-500 italic p-10 border border-dashed border-gray-800 text-center rounded-xl uppercase text-xs">Aguardando geração da tabela de jogos...</div> : (
                      [...new Set(partidas.map(p => p.rodada))].map(r => (
                        <div key={r} className="bg-ef-card p-4 rounded-2xl border border-gray-800">
                          <h5 className="text-ef-green font-bold mb-4 uppercase text-xs italic tracking-widest">Rodada {r}</h5>
                          <div className="space-y-3">
                            {partidas.filter(p => p.rodada === r).map(p => (
                              <div key={p.id} className="flex items-center bg-ef-dark p-3 rounded-xl border border-gray-700">
                                <div className="flex-1 flex justify-end items-center space-x-3 pr-2">
                                  <span className="font-bold text-xs sm:text-sm uppercase">{p.time_casa?.nome}</span>
                                  <img src={p.time_casa?.escudo_url || ''} className="w-8 h-8 rounded-full bg-gray-800" />
                                </div>
                                <div className="flex items-center space-x-2 bg-black px-3 py-1 rounded-md border border-gray-800">
                                  <input readOnly={!canEdit} type="number" defaultValue={p.gols_casa} onBlur={e => canEdit && atualizarPlacar(p.id, parseInt(e.target.value), p.gols_fora)} className="w-6 bg-transparent text-center font-bold text-ef-green outline-none" />
                                  <span className="text-gray-700 font-bold">X</span>
                                  <input readOnly={!canEdit} type="number" defaultValue={p.gols_fora} onBlur={e => canEdit && atualizarPlacar(p.id, p.gols_casa, parseInt(e.target.value))} className="w-6 bg-transparent text-center font-bold text-ef-green outline-none" />
                                </div>
                                <div className="flex-1 flex justify-start items-center space-x-3 pl-2">
                                  <img src={p.time_fora?.escudo_url || ''} className="w-8 h-8 rounded-full bg-gray-800" />
                                  <span className="font-bold text-xs sm:text-sm uppercase">{p.time_fora?.nome}</span>
                                </div>
                              </div>
                            ))}
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                )}

                {activeTab === 'tabela' && (
                  <div className="bg-ef-card rounded-xl border border-gray-800 overflow-hidden shadow-2xl">
                    <table className="w-full text-left">
                      <thead className="bg-gray-900 text-[10px] text-gray-500 uppercase tracking-tighter">
                        <tr><th className="p-4">Pos</th><th className="p-4">Time</th><th className="p-4 text-center">P</th><th className="p-4 text-center">J</th><th className="p-4 text-center">SG</th></tr>
                      </thead>
                      <tbody className="text-sm">
                        {calcularClassificacao().map((t, i) => (
                          <tr key={t.id} className="border-b border-gray-800 hover:bg-black transition">
                            <td className="p-4 font-bold text-gray-500">{i+1}º</td>
                            <td className="p-4 flex items-center space-x-3 font-bold uppercase italic text-xs">
                              <img src={t.escudo_url || ''} className="w-6 h-6 rounded-full bg-gray-800" />
                              <span>{t.nome}</span>
                            </td>
                            <td className="p-4 text-center font-black text-ef-green text-base">{t.p}</td>
                            <td className="p-4 text-center text-gray-500">{t.j}</td>
                            <td className="p-4 text-center font-bold text-gray-300">{t.sg}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
